/**
 * Notification service — orchestrates notification delivery via the EventBus
 * and registered NotificationAdapter implementations.
 *
 * Architecture:
 * - ALL notifications are triggered by AppEvents flowing through the EventBus.
 * - The NotificationService subscribes to relevant events and constructs
 *   NotificationPayloads from them.
 * - Each payload is dispatched to the appropriate NotificationAdapter based
 *   on its channel field.
 * - After delivery, the service emits notification:sent or notification:failed
 *   events for observability.
 *
 * Constraints:
 * - All adapters MUST implement the NotificationAdapter interface.
 * - All notifications MUST go through EventBus.emit() — no direct calls.
 * - To add a new notification trigger, subscribe to the event in registerHandlers().
 * - To add a new delivery channel, implement NotificationAdapter and register it.
 *
 * Depends on:
 * - EventBus (event system) for receiving events and emitting delivery results
 * - NotificationAdapter implementations for actual delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
  NotificationPriority,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (useful for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for a specific channel.
   * Only one adapter per channel is supported; registering a second
   * adapter for the same channel replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to EventBus events that trigger notifications.
   *
   * To add a new notification trigger:
   * 1. Define the event in src/events/event-types.ts
   * 2. Add a handler method that constructs a NotificationPayload
   * 3. Subscribe to the event here
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user via email.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const payload = this.buildPayload({
      type: 'order:confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
    });

    void this.dispatch(payload);
  }

  /**
   * Handle order status change — notify user of update via email.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const payload = this.buildPayload({
      type: 'order:status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: 'normal',
    });

    void this.dispatch(payload);
  }

  /**
   * Build a full NotificationPayload from partial input.
   */
  private buildPayload(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    priority: NotificationPriority;
    metadata?: Record<string, unknown>;
  }): NotificationPayload {
    return {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority,
      createdAt: new Date(),
      metadata: params.metadata,
    };
  }

  /**
   * Dispatch a notification payload to the appropriate adapter.
   * Falls back to in-memory storage if no adapter is registered for the channel.
   */
  private async dispatch(payload: NotificationPayload): Promise<void> {
    // Always store the notification record
    this.storeNotification(payload);

    const adapter = this.adapters.get(payload.channel);
    if (!adapter) {
      this.logger.warn(
        `No adapter registered for channel "${payload.channel}", notification ${payload.id} stored but not delivered`,
      );
      return;
    }

    const result = await adapter.send(payload);

    if (result.success) {
      await this.eventBus.emit({
        type: 'notification:sent',
        payload,
        result,
        timestamp: new Date(),
      });
    } else {
      this.logger.error(`Notification ${payload.id} delivery failed: ${result.error}`);
      await this.eventBus.emit({
        type: 'notification:failed',
        payload,
        result,
        timestamp: new Date(),
      });
    }
  }

  /**
   * Store a notification record in-memory.
   */
  private storeNotification(payload: NotificationPayload): void {
    const notification: Notification = {
      id: payload.id,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      type: payload.type,
      channel: payload.channel,
      priority: payload.priority,
      sentAt: payload.createdAt,
      metadata: payload.metadata,
    };
    this.notifications.push(notification);
    this.logger.info(`Notification stored: ${notification.id} to ${payload.recipient}`);
  }

  /**
   * Get all stored notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of stored notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all stored notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

